37	@Component(
38			service = RESTClient.class,
39			configurationPolicy = ConfigurationPolicy.REQUIRE,
40			immediate = true
41	)
42	@Designate(ocd = RESTClientConfig.class)
43	public class RESTClientImpl implements RESTClient {
44		private static final Logger LOG = LoggerFactory.getLogger(RESTClientImpl.class);
45	
46		private static final String DEFAULT_SERVER_URL = "http://ptcappstg02.isus.emc.com:8080/Thingworx/Things/OneLMS.CourseAggregatorServiceManager/Services";
47	
48		private CloseableHttpClient httpClient;
49	
50		private String serverUrl;
51		private String[] defaultHeaders;
52		private String gUID;
53	
54		public GenericAPIJSONResult execute(EMCRESTCall emcRestCall) throws Exception {
55			HttpUriRequest httpUriRequest = createRequest(emcRestCall);
56			try (CloseableHttpResponse httpApiResponse = this.httpClient.execute(httpUriRequest)) {
57				gUID = "GUID" + (System.currentTimeMillis() - 1);
58				LOG.info("Unq ID : " + gUID + " Start Time :" + System.currentTimeMillis());
59	
60				if (httpApiResponse != null) {
61					return handleHttpResponse(httpApiResponse);
62				}
63			} catch (IOException e) {
64				LOG.error("Failed to obtain a response from REST Server", e);
65				throw new Exception("Failed to obtain a response from REST Server", e);
66			}
67			return null;
68		}
69	
70		private HttpUriRequest createRequest(EMCRESTCall emcRestCall) {
71			RequestBuilder requestBuilder = RequestBuilder.create(emcRestCall.getMethod());
72			String path = emcRestCall.getPath();
73			LOG.debug("URL FOR VALIDATION : " + path);
74			if (StringUtils.isNotEmpty(path) && (path.startsWith("http") || path.startsWith("https"))) {
75				requestBuilder.setUri(path);
76			} else if (StringUtils.isNotEmpty(path)) {
77				requestBuilder.setUri(serverUrl + path);
78				LOG.debug("API FULL URL FOR VALIDATION : " + serverUrl + path);
79			}
80	
81			requestBuilder.addHeader("Accept", emcRestCall.getContentType());
82			if (emcRestCall.hasDefaultHeaders() && defaultHeaders != null) {
83				for (String header : defaultHeaders) {
84					String[] keyValuePair = header.split("\\:");
85					requestBuilder.addHeader(keyValuePair[0], keyValuePair[1]);
86				}
87			}
88			List<Header> headers = emcRestCall.getHeaders();
89			if (headers != null && headers.size() > 0) {
90				for (Header header : headers) {
91					requestBuilder.addHeader(header);
92				}
93			}
94	
95			NameValuePair[] parameters = emcRestCall.getQueryParameters().toArray(new NameValuePair[0]);
96			requestBuilder.addParameters(parameters);
97	
98			if ("POST".equals(emcRestCall.getMethod()) || "PUT".equals(emcRestCall.getMethod())) {
99				requestBuilder.setEntity(emcRestCall.getEntity());
100			}
101			return requestBuilder.build();
102		}
103	
104		public GenericAPIJSONResult handleHttpResponse(HttpResponse httpApiResponse) {
105			HttpEntity entity = httpApiResponse.getEntity();
106	
107			if (entity != null) {
108				try {
109					LOG.info("Unq ID : " + gUID + " END Time :" + System.currentTimeMillis());
110					String responseBody = EntityUtils.toString(entity, "UTF-8");
111					EntityUtils.consume(entity); // Consume the entity to release resources
112					return new GenericAPIJSONResult(httpApiResponse.getStatusLine().getStatusCode(), responseBody);
113				} catch (IOException ioe) {
114					LOG.error("Failed to read response body", ioe);
115				} catch (JsonSyntaxException jse) {
116					LOG.error("Failed to parse response body as JSON", jse);
117				}
118			}
119			return new GenericAPIJSONResult(httpApiResponse.getStatusLine().getStatusCode());
120		}
121	
122		@Activate
123		protected void activate(RESTClientConfig config) {
124			this.serverUrl = config.server_rest_url();
125			this.defaultHeaders = config.api_headers();
126	
127			final HttpClientBuilder httpClientBuilder = HttpClients.custom();
128	
129			// set up SSL connection factory to trust all certificates (if configured)
130			SSLConnectionSocketFactory sslsf = null;
131	
132			// create socket factory registry for connection manager
133			final Registry<ConnectionSocketFactory> socketFactoryRegistry = RegistryBuilder.<ConnectionSocketFactory>create()
134					.register("http", PlainConnectionSocketFactory.getSocketFactory())
135					.register("https", sslsf != null ? sslsf : SSLConnectionSocketFactory.getSocketFactory())
136					.build();
137	
138			// set up connection pool manager
139			final PoolingHttpClientConnectionManager cm = new PoolingHttpClientConnectionManager(socketFactoryRegistry);
140			cm.setMaxTotal(config.api_connections_max());
141			cm.setDefaultMaxPerRoute(config.api_connections_max_host());
142			httpClientBuilder.setConnectionManager(cm);
143	
144			// define default request config used for all requests
145			final RequestConfig rc = RequestConfig.custom()
146					.setCookieSpec(CookieSpecs.IGNORE_COOKIES)
147					.setConnectTimeout(config.connection_timeout())
148					.setConnectionRequestTimeout(config.connection_request_timeout())
149					.setSocketTimeout(config.socket_timeout())
150					.setAuthenticationEnabled(false)
151					.build();
152			httpClientBuilder.setDefaultRequestConfig(rc);
153	
154			httpClient = httpClientBuilder.build();
155			LOG.debug("REST API client set up");
156			LOG.info("Activated RESTClientImpl: ConnectionRequestTimeOut: {}, ConnectionTimeOut: {}, SocketTimeOut: {}",
157					rc.getConnectionRequestTimeout(), rc.getConnectTimeout(), rc.getSocketTimeout());
158		}
159	}

